{"code": "import json
import os
import re

# Load alive bladder cancer patients (BRCA in this dataset)
brca_file_path = locals()['var_functions.query_db:20']
with open(brca_file_path, 'r') as f:
    brca_data = json.load(f)

# Extract alive bladder patients with barcodes
alive_bladder_barcodes = set()
barcode_to_histotype = {}
for record in brca_data:
    desc = record.get("Patient_description", "")
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', str(desc))
    if match and "Alive" in desc:
        barcode = match.group(1)
        histological_type = record.get("histological_type", "Unknown")
        if histological_type == "None" or not histological_type:
            histological_type = "Unspecified"
        alive_bladder_barcodes.add(barcode)
        barcode_to_histotype[barcode] = histological_type

print("__RESULT__:")
print(json.dumps({
    "total_alive_bladder_patients": len(alive_bladder_barcodes),
    "sample_barcodes": list(alive_bladder_barcodes)[:10],
    "sample_histotypes": {b: barcode_to_histotype[b] for b in list(alive_bladder_barcodes)[:5]}
}))"}
